/**
 * Placeholder embedding data.
 *
 * In production, this will be a 30×300 matrix loaded from a static JSON file
 * generated by the build-time data pipeline from Epicure's epicure_cooc.csv.
 *
 * For development, we use random unit vectors. The scoring engine works the same way;
 * results just won't be semantically meaningful until real embeddings are loaded.
 */

/**
 * Generate a random unit vector of given dimension (for development only).
 */
function randomUnitVector(dim: number): number[] {
  const v = Array.from({ length: dim }, () => Math.random() * 2 - 1);
  const magnitude = Math.sqrt(v.reduce((sum, x) => sum + x * x, 0));
  return v.map((x) => x / magnitude);
}

const EMBEDDING_DIM = 300;
const NUM_QUIZ_INGREDIENTS = 30;
const NUM_CUISINES = 8;
const NUM_MODES = 20; // Using 20 placeholder modes for dev

// Quiz ingredient embeddings (30 × 300)
export const EMBEDDINGS: number[][] = Array.from(
  { length: NUM_QUIZ_INGREDIENTS },
  () => randomUnitVector(EMBEDDING_DIM)
);

// Cuisine direction vectors (8 × 300)
export const CUISINE_VECTORS: number[][] = Array.from(
  { length: NUM_CUISINES },
  () => randomUnitVector(EMBEDDING_DIM)
);

// Mode centroids (placeholder: 20 × 300)
export const MODE_CENTROIDS: number[][] = Array.from(
  { length: NUM_MODES },
  () => randomUnitVector(EMBEDDING_DIM)
);

// Mode entries (placeholder labels and members)
export const MODE_ENTRIES: { label: string; members: string[] }[] = [
  { label: "Sweet baking ingredients", members: ["vanilla", "cinnamon", "brown sugar", "butter"] },
  { label: "Fresh Mediterranean herbs", members: ["basil", "oregano", "thyme", "rosemary"] },
