/**
 * Quiz component: shows ingredient cards one at a time and collects ratings.
 */

import { useState } from "react";
import type { QuizCard, Rating, RatingValue } from "../engine/types";

interface QuizScreenProps {
  cards: QuizCard[];
  onComplete: (ratings: Rating[]) => void;
}

type CardResponse = { type: "rated"; value: RatingValue } | { type: "skipped" };

export function QuizScreen({ cards, onComplete }: QuizScreenProps) {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [responses, setResponses] = useState<(CardResponse | null)[]>(
    () => new Array(cards.length).fill(null)
  );

  const currentCard = cards[currentIndex];
  const progress = ((currentIndex + 1) / cards.length) * 100;

  function handleRate(value: RatingValue): void {
    recordResponse({ type: "rated", value });
  }

  function handleSkip(): void {
    recordResponse({ type: "skipped" });
  }

  function recordResponse(response: CardResponse): void {
    const newResponses = [...responses];
    newResponses[currentIndex] = response;
    setResponses(newResponses);

    if (currentIndex < cards.length - 1) {
      setCurrentIndex(currentIndex + 1);
    } else {
      finishQuiz(newResponses);
    }
  }

  function finishQuiz(finalResponses: (CardResponse | null)[]): void {
    const ratings: Rating[] = finalResponses
      .map((r, i) => {
        if (r && r.type === "rated") {
          return { ingredientIndex: i, value: r.value } as Rating;
        }
        return null;
      })
      .filter((r): r is Rating => r !== null);

    onComplete(ratings);
  }

  return (
    <div className="quiz-screen">
      <div className="progress-bar">
        <div className="progress-fill" style={{ width: `${progress}%` }} />
        <span className="progress-text">{currentIndex + 1} / {cards.length}</span>
      </div>

      <div className="card">
        <h2 className="card-name">{currentCard.name}</h2>
        <p className="card-context">{currentCard.context}</p>
      </div>

      <div className="rating-buttons">
        <button className="rate-btn love" onClick={() => handleRate(1)}>
          Love it
        </button>
        <button className="rate-btn fine" onClick={() => handleRate(0)}>
          It's fine
        </button>
        <button className="rate-btn not-for-me" onClick={() => handleRate(-1)}>
          Not for me
        </button>
      </div>

      <div className="skip-buttons">
        <button className="skip-btn" onClick={handleSkip}>
          Can't eat
        </button>
        <button className="skip-btn" onClick={handleSkip}>
          Don't know
        </button>
      </div>
    </div>
  );
}

/**
 * Profile display: shows the user's palate results in plain language.
 */

import type { Profile } from "../engine/types";

interface ProfileViewProps {
  profile: Profile;
  shareUrl: string;
  onShare: () => void;
}

export function ProfileView({ profile, shareUrl, onShare }: ProfileViewProps) {
  const topCuisines = profile.cuisineScores.slice(0, 3);
  const topModes = profile.modeAffinities.slice(0, 5);

  const llmPrompt = generateLlmPrompt(profile);

  return (
    <div className="profile-view">
      <h2>Your Palate Profile</h2>

      <section className="cuisine-section">
        <h3>Your Cuisines</h3>
        {topCuisines.map((cuisine) => (
          <div key={cuisine.direction} className="cuisine-result">
            <strong>{cuisine.label}</strong>
            {cuisine.topContributors.length > 0 && (
              <p className="because">
                Because you loved {cuisine.topContributors.join(", ")}
              </p>
            )}
          </div>
        ))}
      </section>

      <section className="modes-section">
        <h3>Your Flavor Neighborhoods</h3>
        {topModes.map((mode) => (
          <div key={mode.modeIndex} className="mode-result">
            <strong>{mode.label}</strong>
            <p className="mode-examples">
              Think: {mode.examples.join(", ")}
            </p>
          </div>
        ))}
      </section>

      <section className="actions-section">
        <h3>Find Places to Eat</h3>
        <p>Paste this into ChatGPT or any AI assistant to find matching restaurants near you:</p>
        <div className="llm-prompt">
          <pre>{llmPrompt}</pre>
          <button onClick={() => navigator.clipboard.writeText(llmPrompt)}>
            Copy Prompt
          </button>
        </div>
      </section>

      <section className="share-section">
        <h3>Share with a Friend</h3>
        <p>Send your profile link. When they take the quiz, you'll see what you have in common.</p>
        <div className="share-url">
          <input type="text" readOnly value={shareUrl} />
          <button onClick={onShare}>Copy Link</button>
        </div>
      </section>
    </div>
  );
}

/**
 * Generate an LLM prompt from the profile for restaurant finding.
 */
function generateLlmPrompt(profile: Profile): string {
  const cuisines = profile.cuisineScores
    .slice(0, 3)
    .map((c) => c.label)
    .join(", ");

  const flavors = profile.modeAffinities
    .slice(0, 3)
    .map((m) => `${m.label} (like ${m.examples.slice(0, 2).join(", ")})`)
    .join("; ");

  return `I'm looking for restaurant recommendations near me. My taste profile:

- I gravitate toward ${cuisines} cuisines
- I especially enjoy: ${flavors}

Suggest 3-5 restaurants or restaurant types that match these preferences. For each, explain which aspect of my palate it would satisfy.`;
}

/**
 * Comparison view: shows compatibility between two profiles.
 */

import type { Comparison } from "../engine/types";

interface ComparisonViewProps {
  comparison: Comparison;
  friendName?: string;
}

export function ComparisonView({ comparison, friendName = "your friend" }: ComparisonViewProps) {
  const { sharedGround, conflicts, bridges, eatTogether } = comparison;

  return (
    <div className="comparison-view">
      <h2>Your Food Compatibility</h2>

      <section className="shared-section">
        <h3>What You Both Love</h3>
        <p className="summary">{sharedGround.summary}</p>

        {sharedGround.cuisines.length > 0 && (
          <div className="shared-cuisines">
            <h4>Shared cuisines</h4>
            {sharedGround.cuisines.map((c) => (
              <div key={c.direction} className="shared-item">
                <strong>{c.label}</strong>
                {c.topContributors.length > 0 && (
                  <span> — {c.topContributors.slice(0, 3).join(", ")}</span>
                )}
              </div>
            ))}
          </div>
        )}

        {sharedGround.modes.length > 0 && (
          <div className="shared-modes">
            <h4>Shared flavor neighborhoods</h4>
            {sharedGround.modes.map((m) => (
              <div key={m.modeIndex} className="shared-item">
                <strong>{m.label}</strong>
                <span> — {m.examples.slice(0, 3).join(", ")}</span>
              </div>
            ))}
          </div>
        )}
      </section>

      {conflicts.length > 0 && (
        <section className="conflicts-section">
          <h3>Where You Differ</h3>
          {conflicts.map((conflict, i) => (
            <div key={i} className="conflict-item">
              <p>{conflict.summary}</p>
            </div>
          ))}
        </section>
      )}

      {bridges.length > 0 && (
        <section className="bridges-section">
          <h3>Something New to Try Together</h3>
          {bridges.map((bridge, i) => (
            <div key={i} className="bridge-item">
              <p>{bridge.summary}</p>
            </div>
          ))}
        </section>
      )}

      <section className="eat-together-section">
        <h3>Tonight's Suggestion</h3>
        <p className="eat-together">{eatTogether}</p>
      </section>
    </div>
  );
}

