/**
 * Placeholder embedding data.
 *
 * In production, this will be a 30×300 matrix loaded from a static JSON file
 * generated by the build-time data pipeline from Epicure's epicure_cooc.csv.
 *
 * For development, we use random unit vectors. The scoring engine works the same way;
 * results just won't be semantically meaningful until real embeddings are loaded.
 */

/**
 * Generate a random unit vector of given dimension (for development only).
 */
function randomUnitVector(dim: number): number[] {
  const v = Array.from({ length: dim }, () => Math.random() * 2 - 1);
  const magnitude = Math.sqrt(v.reduce((sum, x) => sum + x * x, 0));
  return v.map((x) => x / magnitude);
}

