.card {
  background: var(--bg-card);
  border: none;
  border-radius: 22px;
  padding: 3.25rem 2.25rem 2.75rem;
  text-align: center;
  width: 100%;
  box-shadow: var(--shadow-card);
  will-change: transform;
  position: relative;
  overflow: hidden;
}

.card::before {
  content: '';
  position: absolute;
  top: 0; left: 0; right: 0;
  height: 3px;
  background: linear-gradient(90deg, var(--ember) 0%, rgba(224, 85, 30, 0.3) 100%);
  border-radius: 22px 22px 0 0;
}

.card-enter {
  animation: cardEnter 0.32s cubic-bezier(0.34, 1.56, 0.64, 1) forwards;
}

.card-exit-left {
  animation: cardExitLeft 0.26s cubic-bezier(0.4, 0, 1, 1) forwards;
}

.card-exit-right {
  animation: cardExitRight 0.26s cubic-bezier(0.4, 0, 1, 1) forwards;
}

.card-exit-up {
  animation: cardExitUp 0.24s ease-in forwards;
}

.card-exit-down {
  animation: cardExitDown 0.24s ease-in forwards;
}

@keyframes cardEnter {
  from { opacity: 0; transform: scale(0.93) translateY(14px); }
  to   { opacity: 1; transform: scale(1) translateY(0); }
}

@keyframes cardExitLeft {
  to { opacity: 0; transform: translateX(-110px) rotate(-9deg); }
}

@keyframes cardExitRight {
  to { opacity: 0; transform: translateX(110px) rotate(9deg); }
}

@keyframes cardExitUp {
  to { opacity: 0; transform: translateY(-55px) scale(0.91); }
